
.system-bar {
  display: flex;
  align-items: center;
  padding: 6px 12px;
  background: var(--c-ink);
  color: #e8dcc8;
  font-size: 11px;
  gap: 10px;
}

.system-item {
  display: flex;
  align-items: center;
  gap: 6px;
}

.label {
  color: #9b9080;
  font-size: 10px;
  text-transform: uppercase;
}

.value {
  color: #e8dcc8;
  font-weight: 500;
}

.eternal-heart {
  color: #c9a8e0;
}

.divider {
  width: 1px;
  height: 12px;
  background: #4a4a4a;
}
