
.status-bar {
  width: 100%;
  max-width: 640px;
  background: var(--c-paper);
  border: 1px solid var(--c-border);
  border-radius: 6px;
  font-family: var(--font-main);
  color: var(--c-ink);
  font-size: 12px;
  line-height: 1.4;
  margin: 0 auto;
  overflow: hidden;
}

.characters-row {
  display: flex;
  gap: 1px;
  background: var(--c-border);
}
